// ---------------------------------------------------------------------------
// Tolerance constants
// ---------------------------------------------------------------------------

mod tolerance {
    /// Absolute tolerance for optimizer arithmetic (f64, CPU, few-step).
    pub const F64_OPTIMIZER_CPU: f64 = 1e-10;
    /// Relaxed tolerance for cumulative EMA / SWA arithmetic (f32 accumulation
    /// over many steps can drift slightly).
    pub const F32_EMA_CPU: f32 = 1e-5;
    /// Convergence tolerance margin for property-based tests.
    pub const CONVERGENCE_MARGIN: f64 = 1.1; // allow 10% over the fixture tolerance
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/// Build a scalar (0-D) `Parameter<f64>` with the given value.
fn scalar_param(val: f64) -> Parameter<f64> {
    let t = Tensor::from_storage(TensorStorage::cpu(vec![val]), vec![], true).unwrap();
    Parameter::new(t)
}

/// Build a 1-D `Parameter<f64>` from a slice.
fn param_from(data: &[f64], shape: &[usize]) -> Parameter<f64> {
    Parameter::from_slice(data, shape).unwrap()
}

/// Build a leaf `Tensor<f64>` (no grad) from a slice.
fn t64(data: &[f64], shape: &[usize]) -> Tensor<f64> {
    Tensor::from_storage(TensorStorage::cpu(data.to_vec()), shape.to_vec(), false).unwrap()
}

/// Build a leaf `Tensor<f32>` (no grad) from a slice.
fn t32(data: &[f32], shape: &[usize]) -> Tensor<f32> {
    Tensor::from_storage(TensorStorage::cpu(data.to_vec()), shape.to_vec(), false).unwrap()
}

/// Minimal mock optimizer for GradScaler and SWALR tests (no real params).
struct MockOptimizer<T: Float> {
    lr: f64,
    param_groups: Vec<ParamGroup<T>>,
    step_called: bool,
}

impl<T: Float> MockOptimizer<T> {
    fn new(lr: f64) -> Self {
        Self {
            lr,
            param_groups: Vec::new(),
            step_called: false,
        }
    }
    fn with_params(lr: f64, params: Vec<Parameter<T>>) -> Self {
        let group = ParamGroup::new(params, lr);
        Self {
            lr,
            param_groups: vec![group],
            step_called: false,
        }
    }
}

impl<T: Float> Optimizer<T> for MockOptimizer<T> {
    fn step(&mut self) -> FerrotorchResult<()> {
        self.step_called = true;
        Ok(())
    }
    fn zero_grad(&mut self) -> FerrotorchResult<()> {
        for g in &self.param_groups {
            for p in g.params() {
                p.set_grad(None)?;
            }
        }
        Ok(())
    }
    fn lr(&self) -> f64 {
        self.lr
    }
    fn set_lr(&mut self, lr: f64) {
        self.lr = lr;
    }
    fn param_groups(&self) -> &[ParamGroup<T>] {
        &self.param_groups
    }
    fn param_groups_mut(&mut self) -> &mut [ParamGroup<T>] {
        &mut self.param_groups
    }
    fn add_param_group(&mut self, g: ParamGroup<T>) {
        self.param_groups.push(g);
    }
    fn state_dict(&self) -> FerrotorchResult<OptimizerState> {
        Ok(OptimizerState::new())
    }
    fn load_state_dict(&mut self, _: &OptimizerState) -> FerrotorchResult<()> {
        Ok(())
    }
}

