#[test]
fn ema_single_step_matches_reference() {
    let fx = load_fixtures();
    let f = fx.ema.iter().find(|f| f.kind == "ema_single_step").unwrap();

    let shadow: Vec<f32> = f.initial_shadow.iter().map(|&v| v as f32).collect();
    let param_data: Vec<f32> = f.update_param.iter().map(|&v| v as f32).collect();

    let p = Parameter::from_slice(&shadow, &[shadow.len()]).unwrap();
    let mut ema = ExponentialMovingAverage::new(std::slice::from_ref(&p), f.decay);

    // Simulate optimizer step — update param in-place.
    no_grad(|| unsafe { p.tensor().update_data(&param_data) }).unwrap();
    ema.update(std::slice::from_ref(&p)).unwrap();

    let got = ema.shadow_params()[0].clone();
    for (i, (&g, &exp)) in got.iter().zip(f.expected_after_1.iter()).enumerate() {
        let exp_f32 = exp as f32;
        assert!(
            (g - exp_f32).abs() < tolerance::F32_EMA_CPU,
            "[{}] element {i}: expected {exp_f32}, got {g} (label: {})",
            f.kind,
            f.label
        );
    }
}

