#[test]
fn ema_apply_and_restore_roundtrip() {
    // Property test: apply_shadow swaps in EMA weights; restore swaps them back.
    let p = Parameter::from_slice(&[10.0f32, 20.0], &[2]).unwrap();
    let mut ema = ExponentialMovingAverage::new(std::slice::from_ref(&p), 0.5);

    no_grad(|| unsafe { p.tensor().update_data(&[0.0f32, 0.0]) }).unwrap();
    ema.update(std::slice::from_ref(&p)).unwrap();
    // shadow = 0.5*[10,20] + 0.5*[0,0] = [5, 10]

    ema.apply_shadow(std::slice::from_ref(&p)).unwrap();
    let after_apply = p.data().unwrap().to_vec();
    assert!((after_apply[0] - 5.0f32).abs() < tolerance::F32_EMA_CPU);
    assert!((after_apply[1] - 10.0f32).abs() < tolerance::F32_EMA_CPU);

    ema.restore(std::slice::from_ref(&p)).unwrap();
    let after_restore = p.data().unwrap().to_vec();
    assert!((after_restore[0] - 0.0f32).abs() < tolerance::F32_EMA_CPU);
    assert!((after_restore[1] - 0.0f32).abs() < tolerance::F32_EMA_CPU);
}

