#[test]
fn swa_running_mean_matches_reference() {
    let fx = load_fixtures();
    let f = fx
        .swa
        .iter()
        .find(|f| f.kind == "swa_running_mean")
        .unwrap();

    let p = Parameter::from_slice(&[0.0f32], &[1]).unwrap();
    let mut avg = AveragedModel::new(std::slice::from_ref(&p), AveragingStrategy::Swa);

    for (step_idx, (&checkpoint, &exp)) in f
        .checkpoints
        .iter()
        .zip(f.expected_running.iter())
        .enumerate()
    {
        no_grad(|| unsafe { p.tensor().update_data(&[checkpoint as f32]) }).unwrap();
        avg.update_parameters(std::slice::from_ref(&p)).unwrap();

        let got = avg.averaged_params()[0][0];
        let exp_f32 = exp as f32;
        assert!(
            (got - exp_f32).abs() < 1e-5f32,
            "[swa_running_mean] step {step_idx}: expected {exp_f32}, got {got} (label: {})",
            f.label
        );
    }
}

#[test]
fn swa_identical_checkpoints_converge_to_value() {
    let fx = load_fixtures();
    let f = fx
        .swa
        .iter()
        .find(|f| f.kind == "swa_identical_checkpoints")
        .unwrap();

    let val = f.checkpoint_value as f32;
    let p = Parameter::from_slice(&[val], &[1]).unwrap();
    let mut avg = AveragedModel::new(std::slice::from_ref(&p), AveragingStrategy::Swa);

    for _ in 0..f.n_updates {
        avg.update_parameters(std::slice::from_ref(&p)).unwrap();
    }

    let got = avg.averaged_params()[0][0];
    assert!(
        (got - val).abs() < 1e-5f32,
        "[swa_identical_checkpoints] expected {val}, got {got} (label: {})",
        f.label
    );
}

#[test]
fn swa_ema_strategy_matches_reference() {
    let fx = load_fixtures();
    let f = fx
        .swa
        .iter()
        .find(|f| f.kind == "swa_ema_two_steps")
        .unwrap();

    let p = Parameter::from_slice(&[f.first_checkpoint as f32], &[1]).unwrap();
    let mut avg = AveragedModel::new(
        std::slice::from_ref(&p),
        AveragingStrategy::Ema(f.ema_decay),
    );

    // First update: copies the first checkpoint.
    avg.update_parameters(std::slice::from_ref(&p)).unwrap();

    // Second update: blends with second_checkpoint.
    no_grad(|| unsafe { p.tensor().update_data(&[f.second_checkpoint as f32]) }).unwrap();
    avg.update_parameters(std::slice::from_ref(&p)).unwrap();

    let got = avg.averaged_params()[0][0];
    let exp = f.expected_after_second as f32;
    assert!(
        (got - exp).abs() < 1e-5f32,
        "[swa_ema_two_steps] expected {exp}, got {got} (label: {})",
        f.label
    );
}

#[test]
fn swa_apply_to_sets_param_to_average() {
    // Property test: apply_to copies averaged weights into the parameter.
    let p = Parameter::from_slice(&[1.0f32, 2.0], &[2]).unwrap();
    let mut avg = AveragedModel::new(std::slice::from_ref(&p), AveragingStrategy::Swa);

    // First update: avg = [1, 2].
    avg.update_parameters(std::slice::from_ref(&p)).unwrap();

    // Second update with [3, 4]: avg = [1,2] + ([3,4]-[1,2])/2 = [2, 3].
    no_grad(|| unsafe { p.tensor().update_data(&[3.0f32, 4.0]) }).unwrap();
    avg.update_parameters(std::slice::from_ref(&p)).unwrap();

    avg.apply_to(std::slice::from_ref(&p)).unwrap();
    let data = p.data().unwrap();
    assert!(
        (data[0] - 2.0f32).abs() < 1e-5f32,
        "expected 2.0, got {}",
        data[0]
    );
    assert!(
        (data[1] - 3.0f32).abs() < 1e-5f32,
        "expected 3.0, got {}",
        data[1]
    );
}

