#[test]
fn lbfgs_converges_on_quadratic() {
    let fx = load_fixtures();
    let f = fx
        .lbfgs
        .iter()
        .find(|f| f.kind == "lbfgs_quadratic_convergence")
        .unwrap();

    let p = scalar_param(f.initial_x);
    let mut opt = Lbfgs::new(vec![p], LbfgsConfig::default().with_lr(f.lr));

    for _ in 0..f.n_steps {
        opt.zero_grad().unwrap();
        let x = opt.param_groups()[0].params()[0].tensor().clone();
        let loss = pow(&x, 2.0).unwrap();
        loss.backward().unwrap();
        opt.step().unwrap();
    }

    let val = opt.param_groups()[0].params()[0].tensor().data().unwrap()[0];
    assert!(
        val.abs() < f.convergence_tolerance * tolerance::CONVERGENCE_MARGIN,
        "[lbfgs_quadratic_convergence] expected |x| < {}, got |x| = {} (label: {})",
        f.convergence_tolerance,
        val.abs(),
        f.label
    );
}

#[test]
fn lbfgs_converges_on_multidim_quadratic() {
    let fx = load_fixtures();
    let f = fx
        .lbfgs
        .iter()
        .find(|f| f.kind == "lbfgs_multidim_quadratic_convergence")
        .unwrap();

    let params: Vec<Parameter<f64>> = f.initial_params.iter().map(|&v| scalar_param(v)).collect();
    let mut opt = Lbfgs::new(params, LbfgsConfig::default().with_lr(f.lr));

    for _ in 0..f.n_steps {
        opt.zero_grad().unwrap();
        let a = opt.param_groups()[0].params()[0].tensor().clone();
        let b = opt.param_groups()[0].params()[1].tensor().clone();
        let a_sq = pow(&a, 2.0).unwrap();
        let b_sq = pow(&b, 2.0).unwrap();
        let loss = add(&a_sq, &b_sq).unwrap();
        loss.backward().unwrap();
        opt.step().unwrap();
    }

    for (i, param) in opt.param_groups()[0].params().iter().enumerate() {
        let val = param.tensor().data().unwrap()[0];
        assert!(
            val.abs() < f.convergence_tolerance * tolerance::CONVERGENCE_MARGIN,
            "[lbfgs_multidim] param[{i}]: expected |v| < {}, got |v| = {} (label: {})",
            f.convergence_tolerance,
            val.abs(),
            f.label
        );
    }
}

#[test]
fn lbfgs_strong_wolfe_converges_on_quadratic() {
    // Property test: strong Wolfe line search also converges on x^2.
    let p = scalar_param(5.0);
    let mut opt = Lbfgs::new(
        vec![p],
        LbfgsConfig::default()
            .with_lr(1.0)
            .with_line_search_fn(Some(LineSearchFn::StrongWolfe)),
    );

    for _ in 0..50 {
        let param = opt.param_groups()[0].params()[0].clone();
        opt.step_with_closure(move || {
            let x = param.tensor().clone();
            let loss = pow(&x, 2.0).unwrap();
            loss.backward().unwrap();
            loss.item()
        })
        .unwrap();
    }

    let val = opt.param_groups()[0].params()[0].tensor().data().unwrap()[0];
    assert!(
        val.abs() < 1e-3,
        "[lbfgs_strong_wolfe] expected |x| < 1e-3, got {val}"
    );
}

#[test]
fn lbfgs_history_bounded_by_history_size() {
    // Property test: history never exceeds history_size entries.
    let p = scalar_param(10.0);
    let history_size = 3usize;
    let mut opt = Lbfgs::new(
        vec![p],
        LbfgsConfig::default()
            .with_lr(0.1)
            .with_history_size(history_size),
    );

    for _ in 0..15 {
        opt.zero_grad().unwrap();
        let x = opt.param_groups()[0].params()[0].tensor().clone();
        let loss = pow(&x, 2.0).unwrap();
        loss.backward().unwrap();
        opt.step().unwrap();
    }

    let state = opt.state_dict().unwrap();
    let history_len = state["meta"]["history_len"][0] as usize;
    assert!(
        history_len <= history_size,
        "[lbfgs_history] history_len {history_len} > history_size {history_size}"
    );
}

#[test]
fn lbfgs_step_requires_closure_for_line_search() {
    // Contract test: step() without closure errors when line_search_fn is set.
    let p = scalar_param(1.0);
    let mut opt = Lbfgs::new(
        vec![p],
        LbfgsConfig::default().with_line_search_fn(Some(LineSearchFn::StrongWolfe)),
    );
    let grad = t64(&[1.0], &[]);
    opt.param_groups_mut()[0].params()[0]
        .tensor()
        .set_grad(Some(grad))
        .unwrap();
    let result = opt.step();
    assert!(
        result.is_err(),
        "[lbfgs_contract] step without closure should error"
    );
}

