#[test]
fn grad_scaler_state_dict_roundtrip_matches_reference() {
    let fx = load_fixtures();
    let f = fx
        .grad_scaler
        .iter()
        .find(|f| f.kind == "grad_scaler_state_dict_roundtrip")
        .unwrap();

    let config = GradScalerConfig::default()
        .with_init_scale(f.init_scale)
        .with_growth_interval(10);
    let mut scaler = GradScaler::<f32>::new(config);

    // Advance tracker by 2 healthy steps.
    for _ in 0..2 {
        let p = Parameter::from_slice(&[1.0f32], &[1]).unwrap();
        let grad = t32(&[1.0f32], &[1]);
        p.set_grad(Some(grad)).unwrap();
        let mut opt = MockOptimizer::with_params(0.01, vec![p]);
        scaler.step(&mut opt).unwrap();
        scaler.update();
    }

    let state = scaler.state_dict();
    assert_eq!(
        state.growth_tracker, f.growth_tracker_after_2_steps,
        "[grad_scaler_state_dict] tracker: expected {}, got {} (label: {})",
        f.growth_tracker_after_2_steps, state.growth_tracker, f.label
    );
    assert!(
        (state.scale_factor - f.init_scale).abs() < tolerance::F64_OPTIMIZER_CPU,
        "[grad_scaler_state_dict] scale: expected {}, got {} (label: {})",
        f.init_scale,
        state.scale_factor,
        f.label
    );

    // Round-trip into a fresh scaler.
    let mut scaler2 = GradScaler::<f32>::new(GradScalerConfig::default());
    scaler2.load_state_dict(&state);
    let state2 = scaler2.state_dict();
    assert_eq!(state2.growth_tracker, state.growth_tracker);
    assert!((state2.scale_factor - state.scale_factor).abs() < tolerance::F64_OPTIMIZER_CPU);
}

#[test]
fn grad_scaler_disabled_passthrough() {
    let config = GradScalerConfig::default().with_enabled(false);
    let mut scaler = GradScaler::<f32>::new(config);

    // scale() returns the tensor unchanged.
    let loss = t32(&[5.0f32], &[1]);
    let scaled = scaler.scale(&loss).unwrap();
    assert!(
        (scaled.data().unwrap()[0] - 5.0f32).abs() < 1e-6f32,
        "[grad_scaler_disabled] scale should not modify loss"
    );

    // step() calls the optimizer even with an inf gradient.
    let p = Parameter::from_slice(&[1.0f32], &[1]).unwrap();
    let grad = t32(&[f32::INFINITY], &[1]);
    p.set_grad(Some(grad)).unwrap();
    let mut opt = MockOptimizer::with_params(0.01, vec![p]);
    let stepped = scaler.step(&mut opt).unwrap();
    assert!(stepped, "[grad_scaler_disabled] should always step");
    assert!(
        opt.step_called,
        "[grad_scaler_disabled] optimizer must be called"
    );
}

#[test]
fn grad_scaler_unscale_divides_gradients() {
    // Property test: unscale_ divides each gradient element by scale_factor.
    let scale = 256.0f64;
    let config = GradScalerConfig::default().with_init_scale(scale);
    let mut scaler = GradScaler::<f32>::new(config);

    let p = Parameter::from_slice(&[1.0f32, 2.0, 3.0], &[3]).unwrap();
    let grad = t32(&[256.0f32, 512.0, 768.0], &[3]);
    p.set_grad(Some(grad)).unwrap();

    let mut opt = MockOptimizer::with_params(0.01, vec![p]);
    scaler.unscale_(&mut opt).unwrap();

    let unscaled = opt.param_groups()[0].params()[0].grad().unwrap().unwrap();
    let data = unscaled.data().unwrap();
    assert!(
        (data[0] - 1.0f32).abs() < 1e-5f32,
        "expected 1.0, got {}",
        data[0]
    );
    assert!(
        (data[1] - 2.0f32).abs() < 1e-5f32,
        "expected 2.0, got {}",
        data[1]
    );
    assert!(
        (data[2] - 3.0f32).abs() < 1e-5f32,
        "expected 3.0, got {}",
        data[2]
    );
}

