// Layer 3 — Muon mathematical-property tests
// ===========================================================================

#[test]
fn muon_newton_schulz_produces_orthogonal_matrix() {
    let fx = load_fixtures();
    let f = fx
        .muon
        .iter()
        .find(|f| f.kind == "muon_ns_orthogonality")
        .unwrap();

    // Run a Muon step on a 2x2 parameter with the given input as the gradient
    // (no-momentum, no-nesterov), then verify the parameter moved in an
    // orthogonal direction. We check the property via a direct Newton-Schulz
    // test: construct gradient matrix G, run orthogonalization, verify
    // G_orth^T @ G_orth ≈ I.
    //
    // The Muon internals call `newton_schulz_orthogonalize` but it is private.
    // We drive the property through a Muon step and inspect parameter movement.
    let g_flat: Vec<f64> = f.input.iter().flat_map(|row| row.iter().copied()).collect();
    let p = param_from(&[1.0, 0.0, 0.0, 1.0], &[2, 2]); // identity matrix
    let grad_t =
        Tensor::from_storage(TensorStorage::cpu(g_flat.clone()), vec![2, 2], false).unwrap();
    p.set_grad(Some(grad_t)).unwrap();

    let config = MuonConfig::new(0.1)
        .momentum(0.0)
        .nesterov(false)
        .ns_steps(10);
    let mut muon = Muon::new(vec![p], config);
    muon.step().unwrap();

    // The parameter was updated: param_new = I - lr * G_orth.
    // G_orth should be orthogonal; verify by checking that the update direction
    // satisfies ||G_orth @ G_orth^T - I||_max < tolerance.
    // We extract G_orth = (I - param_new) / lr.
    let param_new = muon.param_groups()[0].params()[0].data().unwrap().to_vec();
    let lr = 0.1f64;
    // g_orth[i] = (identity[i] - param_new[i]) / lr
    let identity = [1.0, 0.0, 0.0, 1.0];
    let g_orth: Vec<f64> = identity
        .iter()
        .zip(param_new.iter())
        .map(|(&id, &pn)| (id - pn) / lr)
        .collect();

    // Compute G_orth^T @ G_orth (should be ~ I for orthogonal G_orth).
    let mut product = [0.0f64; 4];
    for i in 0..2 {
        for j in 0..2 {
            for k in 0..2 {
                product[i * 2 + j] += g_orth[k * 2 + i] * g_orth[k * 2 + j];
            }
        }
    }
    let tol = f.tolerance;
    assert!(
        (product[0] - 1.0).abs() < tol,
        "[muon_ns] (0,0)={} not ~1.0",
        product[0]
    );
    assert!(
        (product[3] - 1.0).abs() < tol,
        "[muon_ns] (1,1)={} not ~1.0",
        product[3]
    );
    assert!(
        product[1].abs() < tol,
        "[muon_ns] (0,1)={} not ~0.0",
        product[1]
    );
    assert!(
        product[2].abs() < tol,
        "[muon_ns] (1,0)={} not ~0.0",
        product[2]
    );
}

#[test]
fn muon_converges_on_quadratic() {
    let fx = load_fixtures();
    let f = fx
        .muon
        .iter()
        .find(|f| f.kind == "muon_convergence_1d")
        .unwrap();

    let init: Vec<f64> = f.initial_param.clone();
    let p = param_from(&init, &[init.len()]);

    let config = MuonConfig::new(f.lr).momentum(0.9).nesterov(true);
    let mut muon = Muon::new(vec![p], config);

    for _ in 0..f.n_steps {
        let current = muon.param_groups()[0].params()[0].data().unwrap().to_vec();
        let grad = Tensor::from_storage(
            TensorStorage::cpu(current.clone()),
            vec![current.len()],
            false,
        )
        .unwrap();
        muon.param_groups_mut()[0].params()[0]
            .set_grad(Some(grad))
            .unwrap();
        muon.step().unwrap();
    }

    let final_data = muon.param_groups()[0].params()[0].data().unwrap().to_vec();
    let norm_sq: f64 = final_data.iter().map(|&x| x * x).sum();
    assert!(
        norm_sq < f.convergence_tolerance_norm_sq * tolerance::CONVERGENCE_MARGIN,
        "[muon_convergence] ||x||^2 = {norm_sq} not < {} (label: {})",
        f.convergence_tolerance_norm_sq,
        f.label
    );
}

#[test]
fn muon_state_dict_roundtrip_preserves_momentum_buffers() {
    // Property test: state_dict/load_state_dict round-trips momentum buffers.
    let p = param_from(&[5.0, 5.0], &[2]);
    let config = MuonConfig::new(0.02).momentum(0.95);
    let mut muon = Muon::new(vec![p], config);

    let grad = Tensor::from_storage(TensorStorage::cpu(vec![1.0f64, 2.0]), vec![2], false).unwrap();
    muon.param_groups_mut()[0].params()[0]
        .set_grad(Some(grad))
        .unwrap();
    muon.step().unwrap();

    let state = muon.state_dict().unwrap();
    assert!(
        !state.is_empty(),
        "[muon_state_dict] should be non-empty after a step"
    );

    let p2 = param_from(&[5.0, 5.0], &[2]);
    let mut muon2 = Muon::new(vec![p2], MuonConfig::new(0.02).momentum(0.95));
    muon2.load_state_dict(&state).unwrap();

    let state2 = muon2.state_dict().unwrap();

    // Element-wise comparison of the momentum buffer — a stub that loads
    // zeros (or any other length-preserving value) is rejected here.
    let buf1: &Vec<f64> = state
        .get("0_0")
        .and_then(|m| m.get("momentum_buffer"))
        .expect("[muon_state_dict] state must contain 0_0/momentum_buffer");
    let buf2: &Vec<f64> = state2
        .get("0_0")
        .and_then(|m| m.get("momentum_buffer"))
        .expect("[muon_state_dict] state2 must contain 0_0/momentum_buffer after load");
    assert_eq!(
        buf1.len(),
        buf2.len(),
        "[muon_state_dict] momentum buffer length must round-trip"
    );
    for (i, (&a, &b)) in buf1.iter().zip(buf2.iter()).enumerate() {
        assert!(
            (a - b).abs() < tolerance::F64_OPTIMIZER_CPU,
            "[muon_state_dict] momentum_buffer[{i}]: original {a} vs round-tripped {b}"
        );
    }
}

