#[test]
fn kfac_factor_update_arithmetic_matches_reference() {
    let fx = load_fixtures();
    let f = fx
        .kfac
        .iter()
        .find(|f| f.kind == "kfac_factor_update")
        .unwrap();

    let n_features = f.activation[0].len();
    let n_batch = f.activation.len();
    let flat_act: Vec<f64> = f
        .activation
        .iter()
        .flat_map(|r| r.iter().copied())
        .collect();
    let act_t = Tensor::from_storage(
        TensorStorage::cpu(flat_act),
        vec![n_batch, n_features],
        false,
    )
    .unwrap();

    // out_features = 1 for simplicity; gradient is all ones.
    let grad_t = Tensor::from_storage(
        TensorStorage::cpu(vec![1.0f64; n_batch]),
        vec![n_batch, 1],
        false,
    )
    .unwrap();

    let p = param_from(&vec![0.0f64; n_features], &[1, n_features]);
    let config = KfacConfig::default().with_momentum(0.0); // no EMA blending
    let mut kfac = Kfac::new(vec![p], config);
    kfac.update_factors("g0_p0", &act_t, &grad_t).unwrap();

    let factors = kfac.state_dict().unwrap();
    let a_factor = factors
        .get("g0_p0")
        .and_then(|e| e.get("a_factor"))
        .expect("a_factor must be present");

    // Diagonal entries should match reference.
    for (i, &exp) in f.expected_a_factor_diag.iter().enumerate() {
        let got = a_factor[i * n_features + i];
        assert!(
            (got - exp).abs() < tolerance::F64_OPTIMIZER_CPU,
            "[kfac_factors] diag[{i}]: expected {exp}, got {got} (label: {})",
            f.label
        );
    }
    // Off-diagonal entries should be ~0 (centered/orthogonal activations).
    // Walk the actual computed matrix and assert each off-diagonal element
    // produced by the implementation is near zero — this catches a stub that
    // populates only the diagonal or returns the identity matrix unchanged.
    for i in 0..n_features {
        for j in 0..n_features {
            if i == j {
                continue;
            }
            let got = a_factor[i * n_features + j];
            assert!(
                got.abs() < tolerance::F64_OPTIMIZER_CPU,
                "[kfac_factors] off-diag[{i},{j}]: expected ~0, got {got} (label: {})",
                f.label
            );
        }
    }
    // Secondary guard: the fixture's recorded off-diagonal expectations are
    // themselves ~0 (so the empirical bound above matches the reference).
    for &exp in &f.expected_a_factor_offdiag {
        assert!(
            exp.abs() < tolerance::F64_OPTIMIZER_CPU,
            "[kfac_factors] off-diag fixture {exp} is not zero (label: {})",
            f.label
        );
    }
}

#[test]
fn kfac_falls_back_to_sgd_without_factors() {
    // Property test: without registered Kronecker factors, K-FAC update
    // equals SGD: param -= lr * grad.
    let lr = 0.1f64;
    let data = vec![1.0, 2.0, 3.0];
    let grad_data = vec![0.1, 0.2, 0.3];

    let p = param_from(&data, &[3]);
    let grad_t =
        Tensor::from_storage(TensorStorage::cpu(grad_data.clone()), vec![3], false).unwrap();
    p.tensor().set_grad(Some(grad_t)).unwrap();

    let config = KfacConfig::default()
        .with_lr(lr)
        .with_momentum(0.0)
        .with_update_freq(1)
        .with_damping(0.0)
        .with_weight_decay(0.0)
        .with_maximize(false);
    let mut kfac = Kfac::new(vec![p], config);
    kfac.step().unwrap();

    let updated = kfac.param_groups()[0].params()[0].data().unwrap().to_vec();
    for (i, (&got, (&orig, &g))) in updated
        .iter()
        .zip(data.iter().zip(grad_data.iter()))
        .enumerate()
    {
        let exp = orig - lr * g;
        assert!(
            (got - exp).abs() < tolerance::F64_OPTIMIZER_CPU,
            "[kfac_sgd_fallback] param[{i}]: expected {exp}, got {got}"
        );
    }
}

#[test]
fn kfac_converges_on_quadratic() {
    // Property test: K-FAC (with SGD fallback) converges on f(x) = x^2.
    let p = scalar_param(5.0);
    let config = KfacConfig::default()
        .with_lr(0.01)
        .with_damping(1e-3)
        .with_momentum(0.0)
        .with_update_freq(1)
        .with_weight_decay(0.0)
        .with_maximize(false);
    let mut kfac = Kfac::new(vec![p], config);

    for _ in 0..1000 {
        kfac.zero_grad().unwrap();
        let tensor = kfac.param_groups()[0].params()[0].tensor().clone();
        let loss = pow(&tensor, 2.0).unwrap();
        loss.backward().unwrap();
        kfac.step().unwrap();
    }

    let val = kfac.param_groups()[0].params()[0].tensor().data().unwrap()[0];
    assert!(
        val.abs() < 0.1,
        "[kfac_convergence] expected |x| < 0.1, got {val}"
    );
}

#[test]
fn kfac_state_dict_roundtrip() {
    // Property test: state_dict/load_state_dict preserves step_count and factors.
    let p = param_from(&[1.0, 2.0, 3.0, 4.0], &[2, 2]);
    let config = KfacConfig::default().with_momentum(0.0).with_update_freq(1);
    let mut kfac = Kfac::new(vec![p], config);

    let act = Tensor::from_storage(
        TensorStorage::cpu(vec![1.0, 0.0, 0.0, 1.0]),
        vec![2, 2],
        false,
    )
    .unwrap();
    let grad_out = Tensor::from_storage(
        TensorStorage::cpu(vec![1.0, 0.0, 0.0, 1.0]),
        vec![2, 2],
        false,
    )
    .unwrap();
    kfac.update_factors("g0_p0", &act, &grad_out).unwrap();

    let grad_t = Tensor::from_storage(
        TensorStorage::cpu(vec![0.1, 0.2, 0.3, 0.4]),
        vec![2, 2],
        false,
    )
    .unwrap();
    kfac.param_groups_mut()[0].params()[0]
        .tensor()
        .set_grad(Some(grad_t))
        .unwrap();
    kfac.step().unwrap();

    let saved = kfac.state_dict().unwrap();
    assert!(
        saved.contains_key("__kfac_meta__"),
        "[kfac_state] meta key must exist"
    );
    assert!(
        saved.contains_key("g0_p0"),
        "[kfac_state] factor key must exist"
    );
    assert_eq!(saved["__kfac_meta__"]["step_count"][0] as usize, 1);

    let p2 = param_from(&[1.0, 2.0, 3.0, 4.0], &[2, 2]);
    let mut kfac2 = Kfac::new(vec![p2], config);
    kfac2.load_state_dict(&saved).unwrap();

    assert_eq!(
        kfac2.state_dict().unwrap()["__kfac_meta__"]["step_count"][0] as usize,
        1
    );
}
